Incase anyone else wants to be able to dynamically generate table objects without importing the python module containing the original model you can do it as follows.  Using the metadata method of retrieving the table object (`ins = Table(tname, metadata, autoload=True).insert().values(**vals)`) doesn't work with `session.add*()`.

```python
from cockroachdb.sqlalchemy import run_transaction
import sqlalchemy.orm

dict_entries = {                'title_dict': [
                    {'title': 'Mr.'},
                    {'title': 'Mrs.'},
                ],
                'sample_type_dict': [
                    {'description': 'Control'},
                    {'description': 'Comparator'},
                ],}

class TableTemp(object):
    def __init__(self, dictionary):
        for k, v in dictionary.items():
            setattr(self, k, v)

def get_table(metadata, name):
    table = metadata.tables[name]
    cls = type(name.title(), (TableTemp,), {})
    sqlalchemy.orm.mapper(cls, table)
    return cls

def populate_dicts(Base, engine):
    to_insert = []
    for tname in dict_entries:
        this_table = get_table(Base.metadata, tname)
        for vals in dict_entries[tname]:
            to_insert.append(this_table(vals))

    sessionmaker = sqlalchemy.orm.sessionmaker(engine)

    def callback(session):
        session.add_all(to_insert)
    run_transaction(sessionmaker, callback)
```

